import{f as t,o as e,c as s,a9 as r}from"./chunks/framework.BSdZLMbP.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段16-Go与前端交互架构.md","filePath":"S6-Go/阶段16-Go与前端交互架构.md","lastUpdated":1780660866000}'),a={name:"S6-Go/阶段16-Go与前端交互架构.md"};function n(l,o,d,i,g,c){return e(),s("div",null,[...o[0]||(o[0]=[r('<h2 id="🌐-阶段十六-go-与前端交互架构" tabindex="-1">🌐 阶段十六：Go 与前端交互架构 <a class="header-anchor" href="#🌐-阶段十六-go-与前端交互架构" aria-label="Permalink to &quot;🌐 阶段十六：Go 与前端交互架构&quot;">​</a></h2><h3 id="_16-1-bff-与-ssr" tabindex="-1">16.1 BFF 与 SSR <a class="header-anchor" href="#_16-1-bff-与-ssr" aria-label="Permalink to &quot;16.1 BFF 与 SSR&quot;">​</a></h3><h4 id="q62-go-如何作为-bff-backend-for-frontend-层-与-node-js-bff-对比优劣" tabindex="-1">Q62: Go 如何作为 BFF（Backend for Frontend）层？与 Node.js BFF 对比优劣？ <a class="header-anchor" href="#q62-go-如何作为-bff-backend-for-frontend-层-与-node-js-bff-对比优劣" aria-label="Permalink to &quot;Q62: Go 如何作为 BFF（Backend for Frontend）层？与 Node.js BFF 对比优劣？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：聚合接口、协议转换、性能对比、团队协同。</p><p><strong>💡 记忆关键词</strong>：接口聚合、高并发强、类型安全、Node 生态好</p><p><strong>答案要点</strong>：</p><ul><li><strong>Go BFF 优势</strong>：高并发处理能力强、CPU 密集型任务快、部署简单（单二进制）、类型安全。</li><li><strong>Node.js BFF 优势</strong>：前后端语言统一、JSON 处理天然友好、生态丰富（Next.js/Nuxt.js 集成）。</li><li><strong>适用场景</strong>：Go 适合复杂聚合逻辑、高流量网关、微服务编排；Node.js 适合快速迭代、SSR 渲染、前端主导项目。</li><li><strong>实践</strong>：Go 使用 <code>gin</code>/<code>echo</code> 聚合多个微服务接口，统一错误码、格式化响应、缓存热点数据。</li></ul><h4 id="q63-go-如何实现服务端渲染-ssr-与前端框架如何协同" tabindex="-1">Q63: Go 如何实现服务端渲染（SSR）？与前端框架如何协同？ <a class="header-anchor" href="#q63-go-如何实现服务端渲染-ssr-与前端框架如何协同" aria-label="Permalink to &quot;Q63: Go 如何实现服务端渲染（SSR）？与前端框架如何协同？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📖 了解</p><p><strong>考点</strong>：<code>html/template</code>、组件化、 hydration、性能权衡。</p><p><strong>💡 记忆关键词</strong>：html/template、首屏渲染、hydration 接管、templ 引擎</p><p><strong>答案要点</strong>：</p><ul><li>Go 原生支持 <code>html/template</code>，可渲染 HTML 并注入数据。</li><li><strong>现代架构</strong>：Go 提供 API + 静态资源，前端使用 React/Vue 做 CSR；或 Go 渲染首屏 HTML，前端 hydration 接管交互。</li><li><strong>工具链</strong>：<code>templ</code>（类型安全模板引擎）、<code>htmx</code>（轻量级交互，无需 JS 框架）。</li><li><strong>优势</strong>：首屏加载快、SEO 友好、降低前端 bundle 体积。</li></ul><h3 id="_16-2-webassembly-wasm" tabindex="-1">16.2 WebAssembly (Wasm) <a class="header-anchor" href="#_16-2-webassembly-wasm" aria-label="Permalink to &quot;16.2 WebAssembly (Wasm)&quot;">​</a></h3><h4 id="q64-go-编译为-webassembly-的应用场景与限制" tabindex="-1">Q64: Go 编译为 WebAssembly 的应用场景与限制？ <a class="header-anchor" href="#q64-go-编译为-webassembly-的应用场景与限制" aria-label="Permalink to &quot;Q64: Go 编译为 WebAssembly 的应用场景与限制？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📖 了解</p><p><strong>考点</strong>：<code>GOOS=js GOARCH=wasm</code>、性能对比、生态兼容性。</p><p><strong>💡 记忆关键词</strong>：浏览器计算、体积大、TinyGo 优化、JS 桥接</p><p><strong>答案要点</strong>：</p><ul><li><strong>场景</strong>：浏览器端运行复杂计算（图像处理、加密、游戏逻辑）、复用 Go 业务逻辑、边缘计算。</li><li><strong>限制</strong>：Wasm 二进制体积大（Go 运行时 ~2MB+）、DOM 操作需 JS 桥接、启动慢于原生 JS。</li><li><strong>优化</strong>：使用 <code>tinygo</code> 编译（体积可降至 KB 级）、按需加载、与 JS 共享内存。</li></ul><hr>',22)])])}const m=t(a,[["render",n]]);export{p as __pageData,m as default};
